import React, { useState, useEffect } from 'react';
import { videoService } from '../../services/videoService';

const VideoManager = () => {
    const [videos, setVideos] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showAddForm, setShowAddForm] = useState(false);
    const [editingVideo, setEditingVideo] = useState(null);
    const [message, setMessage] = useState({ type: '', text: '' });
    const [newVideo, setNewVideo] = useState({
        title: '',
        description: '',
        video_url: '',
        video_type: 'youtube',
        duration: '',
        status: 'active',
        display_order: 0
    });

    useEffect(() => {
        loadVideos();
    }, []);

    const loadVideos = async () => {
        try {
            const response = await videoService.getAll(false);
            if (response.success) {
                setVideos(response.data);
            }
        } catch (error) {
            showMessage('error', 'Failed to load videos');
        } finally {
            setLoading(false);
        }
    };

    const showMessage = (type, text) => {
        setMessage({ type, text });
        setTimeout(() => setMessage({ type: '', text: '' }), 3000);
    };

    const handleAddVideo = async () => {
        if (!newVideo.title || !newVideo.video_url) {
            showMessage('error', 'Please fill title and video URL');
            return;
        }

        try {
            const response = await videoService.create(newVideo);
            if (response.success) {
                showMessage('success', 'Video added successfully');
                setShowAddForm(false);
                setNewVideo({
                    title: '',
                    description: '',
                    video_url: '',
                    video_type: 'youtube',
                    duration: '',
                    status: 'active',
                    display_order: 0
                });
                loadVideos();
            }
        } catch (error) {
            showMessage('error', error.response?.data?.message || 'Failed to add video');
        }
    };

    const handleUpdateVideo = async () => {
        if (!editingVideo.title || !editingVideo.video_url) {
            showMessage('error', 'Please fill title and video URL');
            return;
        }

        try {
            const response = await videoService.update(editingVideo.id, editingVideo);
            if (response.success) {
                showMessage('success', 'Video updated successfully');
                setEditingVideo(null);
                loadVideos();
            }
        } catch (error) {
            showMessage('error', error.response?.data?.message || 'Failed to update video');
        }
    };

    const handleDeleteVideo = async (id, title) => {
        if (window.confirm(`Are you sure you want to delete "${title}"?`)) {
            try {
                const response = await videoService.delete(id);
                if (response.success) {
                    showMessage('success', 'Video deleted successfully');
                    loadVideos();
                }
            } catch (error) {
                showMessage('error', error.response?.data?.message || 'Failed to delete video');
            }
        }
    };

    const getYouTubeEmbedUrl = (url) => {
        if (url.includes('youtube.com/watch?v=')) {
            const videoId = url.split('v=')[1].split('&')[0];
            return `https://www.youtube.com/embed/${videoId}`;
        }
        if (url.includes('youtu.be/')) {
            const videoId = url.split('youtu.be/')[1].split('?')[0];
            return `https://www.youtube.com/embed/${videoId}`;
        }
        return url;
    };

    if (loading) {
        return (
            <div style={{ textAlign: 'center', padding: '2rem' }}>
                <div className="spinner"></div>
                <p>Loading videos...</p>
            </div>
        );
    }

    return (
        <div className="video-manager">
            <div className="section-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                <h2><i className="fas fa-video"></i> Video Manager</h2>
                <button
                    onClick={() => setShowAddForm(!showAddForm)}
                    style={{
                        padding: '0.6rem 1.2rem',
                        background: '#28a745',
                        color: 'white',
                        border: 'none',
                        borderRadius: '6px',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.5rem'
                    }}
                >
                    <i className="fas fa-plus"></i> Add Video
                </button>
            </div>

            {message.text && (
                <div style={{
                    padding: '1rem',
                    marginBottom: '1rem',
                    borderRadius: '8px',
                    backgroundColor: message.type === 'success' ? '#d4edda' : '#f8d7da',
                    color: message.type === 'success' ? '#155724' : '#721c24',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.5rem'
                }}>
                    <i className={`fas fa-${message.type === 'success' ? 'check-circle' : 'exclamation-circle'}`}></i>
                    {message.text}
                </div>
            )}

            {showAddForm && (
                <div style={{
                    background: 'white',
                    borderRadius: '12px',
                    padding: '1.5rem',
                    marginBottom: '1.5rem',
                    boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                }}>
                    <h3 style={{ marginBottom: '1rem' }}>Add New Video</h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1rem' }}>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.3rem', fontWeight: 'bold' }}>Title *</label>
                            <input
                                type="text"
                                value={newVideo.title}
                                onChange={(e) => setNewVideo({...newVideo, title: e.target.value})}
                                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.3rem', fontWeight: 'bold' }}>Video Type</label>
                            <select
                                value={newVideo.video_type}
                                onChange={(e) => setNewVideo({...newVideo, video_type: e.target.value})}
                                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                            >
                                <option value="youtube">YouTube</option>
                                <option value="vimeo">Vimeo</option>
                                <option value="local">Local</option>
                            </select>
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.3rem', fontWeight: 'bold' }}>Video URL *</label>
                            <input
                                type="url"
                                placeholder="https://..."
                                value={newVideo.video_url}
                                onChange={(e) => setNewVideo({...newVideo, video_url: e.target.value})}
                                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.3rem', fontWeight: 'bold' }}>Description</label>
                            <textarea
                                rows="2"
                                value={newVideo.description}
                                onChange={(e) => setNewVideo({...newVideo, description: e.target.value})}
                                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                            ></textarea>
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.3rem', fontWeight: 'bold' }}>Display Order</label>
                            <input
                                type="number"
                                value={newVideo.display_order}
                                onChange={(e) => setNewVideo({...newVideo, display_order: parseInt(e.target.value)})}
                                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', marginBottom: '0.3rem', fontWeight: 'bold' }}>Status</label>
                            <select
                                value={newVideo.status}
                                onChange={(e) => setNewVideo({...newVideo, status: e.target.value})}
                                style={{ width: '100%', padding: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                            >
                                <option value="active">Active</option>
                                <option value="inactive">Inactive</option>
                            </select>
                        </div>
                    </div>
                    <div style={{ display: 'flex', gap: '1rem', marginTop: '1rem', justifyContent: 'flex-end' }}>
                        <button
                            onClick={handleAddVideo}
                            style={{
                                padding: '0.5rem 1.2rem',
                                background: '#003366',
                                color: 'white',
                                border: 'none',
                                borderRadius: '6px',
                                cursor: 'pointer'
                            }}
                        >
                            <i className="fas fa-save"></i> Add Video
                        </button>
                        <button
                            onClick={() => setShowAddForm(false)}
                            style={{
                                padding: '0.5rem 1.2rem',
                                background: '#6c757d',
                                color: 'white',
                                border: 'none',
                                borderRadius: '6px',
                                cursor: 'pointer'
                            }}
                        >
                            Cancel
                        </button>
                    </div>
                </div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))', gap: '1.5rem' }}>
                {videos.map(video => (
                    <div key={video.id} style={{
                        background: 'white',
                        borderRadius: '12px',
                        overflow: 'hidden',
                        boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                    }}>
                        {editingVideo?.id === video.id ? (
                            <div style={{ padding: '1rem' }}>
                                <input
                                    type="text"
                                    value={editingVideo.title}
                                    onChange={(e) => setEditingVideo({...editingVideo, title: e.target.value})}
                                    placeholder="Title"
                                    style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                                />
                                <select
                                    value={editingVideo.video_type}
                                    onChange={(e) => setEditingVideo({...editingVideo, video_type: e.target.value})}
                                    style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                                >
                                    <option value="youtube">YouTube</option>
                                    <option value="vimeo">Vimeo</option>
                                </select>
                                <input
                                    type="url"
                                    value={editingVideo.video_url}
                                    onChange={(e) => setEditingVideo({...editingVideo, video_url: e.target.value})}
                                    placeholder="URL"
                                    style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                                />
                                <textarea
                                    value={editingVideo.description}
                                    onChange={(e) => setEditingVideo({...editingVideo, description: e.target.value})}
                                    placeholder="Description"
                                    rows="2"
                                    style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                                ></textarea>
                                <select
                                    value={editingVideo.status}
                                    onChange={(e) => setEditingVideo({...editingVideo, status: e.target.value})}
                                    style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem', border: '1px solid #ddd', borderRadius: '4px' }}
                                >
                                    <option value="active">Active</option>
                                    <option value="inactive">Inactive</option>
                                </select>
                                <div style={{ display: 'flex', gap: '0.5rem' }}>
                                    <button
                                        onClick={handleUpdateVideo}
                                        style={{ flex: 1, padding: '0.5rem', background: '#28a745', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
                                    >
                                        <i className="fas fa-check"></i> Save
                                    </button>
                                    <button
                                        onClick={() => setEditingVideo(null)}
                                        style={{ flex: 1, padding: '0.5rem', background: '#6c757d', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
                                    >
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <>
                                <div style={{ height: '200px', background: '#000', position: 'relative' }}>
                                    <iframe
                                        src={getYouTubeEmbedUrl(video.video_url)}
                                        title={video.title}
                                        frameBorder="0"
                                        allowFullScreen
                                        style={{ width: '100%', height: '100%' }}
                                    ></iframe>
                                </div>
                                <div style={{ padding: '1rem' }}>
                                    <h4 style={{ marginBottom: '0.5rem' }}>{video.title}</h4>
                                    <p style={{ fontSize: '0.85rem', color: '#666', marginBottom: '0.5rem' }}>{video.description}</p>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: '0.8rem' }}>
                                        <span><i className="fas fa-play-circle"></i> {video.video_type}</span>
                                        <span style={{
                                            padding: '0.2rem 0.5rem',
                                            borderRadius: '12px',
                                            backgroundColor: video.status === 'active' ? '#d4edda' : '#f8d7da',
                                            color: video.status === 'active' ? '#155724' : '#721c24'
                                        }}>
                                            {video.status}
                                        </span>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', borderTop: '1px solid #eee' }}>
                                    <button
                                        onClick={() => setEditingVideo(video)}
                                        style={{ flex: 1, padding: '0.8rem', background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                                    >
                                        <i className="fas fa-edit"></i> Edit
                                    </button>
                                    <button
                                        onClick={() => handleDeleteVideo(video.id, video.title)}
                                        style={{ flex: 1, padding: '0.8rem', background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', color: '#dc3545' }}
                                    >
                                        <i className="fas fa-trash"></i> Delete
                                    </button>
                                </div>
                            </>
                        )}
                    </div>
                ))}
            </div>

            {videos.length === 0 && !loading && (
                <div style={{ textAlign: 'center', padding: '3rem' }}>
                    <i className="fas fa-video" style={{ fontSize: '3rem', color: '#ccc', marginBottom: '1rem' }}></i>
                    <h3>No Videos</h3>
                    <p>Add promotional videos to display on the TV dashboard.</p>
                </div>
            )}
        </div>
    );
};

export default VideoManager;
